    async shutdown(): Promise<void> {
      // D4: idempotent — second and subsequent calls are no-ops. The
      // guard is checked first so a re-entrant caller (e.g. a SIGINT
      // arriving while a SIGTERM-driven shutdown is in flight) does
      // not double-fire `guild:shutdown` or double-invoke `stop()`.
      if (shuttingDown) return;
      shuttingDown = true;

      const failures = await shutdownStartedApparatuses(
        startedApparatuses,
        eventHandlers,
      );

      // D6: clear the singleton as the last act regardless of whether
      // any stop() threw. Subsequent guild() calls fail loudly with
      // the existing "Guild not initialized" error rather than handing
      // out stale references.
      clearGuild();

      // D3: re-throw a single aggregate error if any stop() threw,
      // matching the codebase's "collect failures, then act" pattern.
      if (failures.length > 0) {
        const aggregate = new Error(formatShutdownFailures(failures));
        // Attach the per-apparatus failures so callers can introspect.
        (aggregate as Error & { failures: typeof failures }).failures = failures;
        throw aggregate;
      }
    },
  };
  setGuild(guildInstance);

  // Start each apparatus in dependency order
  for (const app of orderedApparatuses) {
    // Register provides before start() so apparatuses with eager provides are
    // visible to later startups that run during this loop.
    if (app.apparatus.provides !== undefined) {
      provides.set(app.id, app.apparatus.provides);
    }

    await app.apparatus.start(startupCtx);

    // Re-check after start() for deferred provides (e.g. Stacks uses a getter
    // that returns undefined until start() populates the backing variable).
    if (!provides.has(app.id) && app.apparatus.provides !== undefined) {
      provides.set(app.id, app.apparatus.provides);
    }

    // Add to started list BEFORE firing event
    startedApparatuses.push(app);

    // Fire apparatus:started (replaces plugin:initialized — no deprecation period)
    await fireEvent(eventHandlers, "apparatus:started", app);
  }

  // Fire phase:started after all apparatus start + events complete
  await fireEvent(eventHandlers, "phase:started");

  return guildInstance;
}

