import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import { multiplySafely } from './numeric.ts';

describe('multiplySafely', () => {
  it('returns the product for a typical multiplication', () => {
    assert.equal(multiplySafely(6, 7), 42);
  });

  it('returns null when the result would overflow Number.MAX_SAFE_INTEGER', () => {
    assert.equal(multiplySafely(Number.MAX_SAFE_INTEGER, 2), null);
  });

  it('returns the product when the result is exactly Number.MAX_SAFE_INTEGER', () => {
    // Number.MAX_SAFE_INTEGER = 9007199254740991 = 1 * 9007199254740991
    assert.equal(multiplySafely(1, Number.MAX_SAFE_INTEGER), Number.MAX_SAFE_INTEGER);
  });
});

