--- /dev/null
+++ b/packages/framework/core/src/util/numeric.ts
@@ -0,0 +1,12 @@
+/**
+ * Returns `a * b` when the result is within the safe-integer range
+ * (`Number.MAX_SAFE_INTEGER`), or `null` when the multiplication would
+ * overflow that bound.
+ */
+export function multiplySafely(a: number, b: number): number | null {
+  const product = a * b;
+  if (Math.abs(product) > Number.MAX_SAFE_INTEGER) {
+    return null;
+  }
+  return product;
+}

